const express = require('express');
const twilio = require('twilio')(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);
const app = express();

app.use((req, res, next) => {
  if (req.session && req.session.user) {
    const code = Math.floor(Math.random() * 1000000).toString().substring(0, 6);
    twilio.messages.create({
      to: req.body.phoneNumber,
      from: process.env.TWILIO_PHONE_NUMBER,
      body: `Your verification code is ${code}`
    }).then(() => {
      req.session.user.verificationCode = code;
      next();
    });
  } else {
    next();
  }
});

app.post('/login', (req, res) => {
  if (req.body.phoneNumber && req.body.password) {
    // Check if the user exists in the database
    const user = findUserByPhoneNumber(req.body.phoneNumber);
    if (!user) {
      res.status(401).send('Invalid phone number');
      return;
    }

    // Verify the password
    if (user.password !== req.body.password) {
      res.status(401).send('Invalid password');
      return;
    }

    // If the user is valid, generate a new verification code and send it to the user's phone number
    const code = Math.floor(Math.random() * 1000000).toString().substring(0, 6);
    twilio.messages.create({
      to: req.body.phoneNumber,
      from: process.env.TWILIO_PHONE_NUMBER,
      body: `Your verification code is ${code}`
    }).then(() => {
      req.session.user.verificationCode = code;
      res.send('Logged in successfully');
    });
  } else {
    res.status(401).send('Invalid request body');
  }
});

app.post('/verify', (req, res) => {
  if (req.body.phoneNumber && req.body.verificationCode) {
    // Check if the user exists in the database
    const user = findUserByPhoneNumber(req.body.phoneNumber);
    if (!user) {
      res.status(401).send('Invalid phone number');
      return;
    }

    // Verify the verification code
    if (user.verificationCode !== req.body.verificationCode) {
      res.status(401).send('Invalid verification code');
      return;
    }

    // If the user is valid and the verification code is correct, log them in
    req.session.user = user;
    res.send('Logged in successfully');
  } else {
    res.status(401).send('Invalid request body');
  }
});